/* ============================================================
   ГЕНЕРАТОР ЛИЦ (плоские векторные аватарки; на этапе 5 заменимы фото)
   o = {g:'m'|'f', skin, hair, style:'short'|'side'|'long'|'bob'|'bun', beard}
   ============================================================ */
function makeFace(o){
  const hairP = {
    short:`<path d="M15 33 Q14 11 32 11 Q50 11 49 33 Q48 21 32 19 Q16 21 15 33Z" fill="${o.hair}"/>`,
    side:`<path d="M15 33 Q14 11 32 11 Q50 11 49 33 Q49 20 38 18 Q30 24 16 24 Q15 28 15 33Z" fill="${o.hair}"/>`,
    long:`<path d="M12 54 Q9 15 32 11 Q55 15 52 54 L43 54 Q49 32 32 22 Q15 32 21 54Z" fill="${o.hair}"/>`,
    bob:`<path d="M13 45 Q11 12 32 11 Q53 12 51 45 Q46 48 44 41 Q49 24 32 20 Q15 24 20 41 Q18 48 13 45Z" fill="${o.hair}"/>`,
    bun:`<circle cx="32" cy="9" r="6" fill="${o.hair}"/><path d="M15 33 Q14 12 32 12 Q50 12 49 33 Q48 21 32 19 Q16 21 15 33Z" fill="${o.hair}"/>`
  }[o.style]||'';
  const beard = o.beard?`<path d="M21 40 Q22 52 32 52 Q42 52 43 40 Q43 48 32 49 Q21 48 21 40Z" fill="${o.hair}" opacity=".85"/>`:'';
  const blush = o.g==='f'?`<circle cx="23" cy="39" r="2.4" fill="#F0A3A3" opacity=".45"/><circle cx="41" cy="39" r="2.4" fill="#F0A3A3" opacity=".45"/>`:'';
  return `<svg viewBox="0 0 64 64" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">
    <rect width="64" height="64" fill="#EEF0FF"/>
    <ellipse cx="32" cy="35" rx="16" ry="17" fill="${o.skin}"/>
    <ellipse cx="16.5" cy="35" rx="2.6" ry="3.4" fill="${o.skin}"/>
    <ellipse cx="47.5" cy="35" rx="2.6" ry="3.4" fill="${o.skin}"/>
    ${hairP}${beard}
    <circle cx="25.5" cy="34" r="1.9" fill="#241F31"/><circle cx="38.5" cy="34" r="1.9" fill="#241F31"/>
    <path d="M22.5 29.5 Q25.5 28 28.5 29.5" stroke="#241F31" stroke-width="1.6" fill="none" stroke-linecap="round"/>
    <path d="M35.5 29.5 Q38.5 28 41.5 29.5" stroke="#241F31" stroke-width="1.6" fill="none" stroke-linecap="round"/>
    <path d="M31 36 Q32 39.5 33.2 36.6" stroke="${o.g==='f'?'#C98A6B':'#B07B52'}" stroke-width="1.4" fill="none" stroke-linecap="round"/>
    <path d="M27 43.5 Q32 47 37 43.5" stroke="#7A4B3A" stroke-width="1.8" fill="none" stroke-linecap="round"/>
    ${blush}
  </svg>`;
}
