document.querySelectorAll('[data-modal]').forEach(el=>{
  el.addEventListener('click', e=>{
    e.preventDefault();
    document.getElementById(el.dataset.modal).classList.add('open');
    document.body.style.overflow='hidden';
  });
});
document.querySelectorAll('.modal').forEach(m=>{
  m.querySelector('.modal-close').addEventListener('click',()=>{m.classList.remove('open');document.body.style.overflow='';});
  m.addEventListener('click',e=>{ if(e.target===m){m.classList.remove('open');document.body.style.overflow='';} });
});
document.addEventListener('keydown',e=>{ if(e.key==='Escape'){document.querySelectorAll('.modal.open').forEach(m=>m.classList.remove('open'));document.body.style.overflow='';} });

