const I_KEYS={ /* переводы для элементов с data-i */
login:{kz:'Кіру',en:'Log in'}, match:{kz:'сәйкестік',en:'match'},
s3big:{kz:'2 есе',en:'2×'}, s3res:{kz:'классикалық агенттіктерден жылдам әрі арзан',en:'faster and cheaper than traditional agencies'},
evreg:{kz:'Тіркелу',en:'Register'}, evmore:{kz:'Толығырақ →',en:'Details →'},
consentLink:{kz:'',en:''}, fPrivacy:{kz:'Құпиялылық саясаты',en:'Privacy Policy'}, fTerms:{kz:'Жария оферта',en:'Public Offer'},
demoTitle:{kz:'ЖИ-сорсинг кандидатов',en:'AI candidate sourcing'},
};

const RU_STORE=new Map();
function applyOne(el, val, mode){
  if(mode==='p'){ if(!RU_STORE.has(el))RU_STORE.set(el,{v:el.placeholder,m:'p'}); el.placeholder = val ?? RU_STORE.get(el).v; return; }
  if(mode==='q'){ if(!RU_STORE.has(el))RU_STORE.set(el,{v:el.childNodes[0].nodeValue,m:'q'}); el.childNodes[0].nodeValue = val ?? RU_STORE.get(el).v; return; }
  if(mode==='h'){ if(!RU_STORE.has(el))RU_STORE.set(el,{v:el.innerHTML,m:'h'}); el.innerHTML = val ?? RU_STORE.get(el).v; if(val)el.querySelectorAll('[data-modal]').forEach(bindModal); return; }
  if(!RU_STORE.has(el))RU_STORE.set(el,{v:el.textContent,m:'t'});
  el.textContent = val ?? RU_STORE.get(el).v;
}
function bindModal(el){
  if(el.dataset.bound)return; el.dataset.bound=1;
  el.addEventListener('click',e=>{e.preventDefault();document.getElementById(el.dataset.modal).classList.add('open');document.body.style.overflow='hidden';});
}
function setLang(lang){
  curLang=lang;
  document.documentElement.lang = lang==='kz'?'kk':lang;
  document.querySelectorAll('.lng').forEach(b=>b.classList.toggle('active',b.dataset.lang===lang));
  const idx = lang==='kz'?1:(lang==='en'?2:null);
  APPLY.forEach(([sel,kz,en,mode])=>{ const el=document.querySelector(sel); if(!el)return; applyOne(el, lang==='ru'?null:(lang==='kz'?kz:en), mode); });
  APPLY_ALL.forEach(([sel,kz,en,mode])=>{ document.querySelectorAll(sel).forEach(el=>applyOne(el, lang==='ru'?null:(lang==='kz'?kz:en), mode)); });
  document.querySelectorAll('[data-i]').forEach(el=>{
    const k=el.dataset.i; if(!(k in I_KEYS))return;
    applyOne(el, lang==='ru'?null:I_KEYS[k][lang], 't');
  });
  document.querySelectorAll('[data-lang-block]').forEach(b=>b.classList.toggle('on', b.dataset.langBlock===lang));
  ['noteP','noteT'].forEach(id=>{ const n=document.getElementById(id); n.textContent=LBL[lang].legalNote; n.classList.toggle('show', lang!=='ru'); });
  document.querySelectorAll('.faq-item.open .faq-a').forEach(a=>a.style.maxHeight=a.scrollHeight+'px');
  const ph=document.querySelector('#typedText .placeholder'); if(ph)ph.textContent=LBL[lang].ph;
  const y=document.getElementById('year'); if(y)y.textContent=new Date().getFullYear();
}
document.querySelectorAll('.lng').forEach(b=>b.addEventListener('click',()=>setLang(b.dataset.lang)));

