let sIdx=0;
const sleep=ms=>new Promise(r=>setTimeout(r,ms));
const reducedMotion=window.matchMedia("(prefers-reduced-motion: reduce)").matches;
async function typeText(el,text){el.textContent="";for(const ch of text){el.textContent+=ch;await sleep(30+Math.random()*40);}}
function animateRing(ringEl,innerEl,target,duration=1100){
  const start=performance.now();
  function frame(now){const t=Math.min((now-start)/duration,1);const val=Math.round((1-Math.pow(1-t,3))*target);
    ringEl.style.setProperty('--p',val);innerEl.textContent=val+"%";if(t<1)requestAnimationFrame(frame);}
  requestAnimationFrame(frame);
}
function buildCard(c){
  const card=document.createElement("div");card.className="candidate";
  card.innerHTML=`<div class="avatar"><img src="${PHOTO[c.photo]}" alt=""></div>
    <div class="candidate-info"><div class="candidate-name">${c.name}</div>
    <div class="candidate-meta">${c.meta}</div>
    <div class="skills">${c.skills.map(s=>`<span class="skill">${s}</span>`).join("")}</div></div>
    <div class="match"><div class="ring2" style="--p:0"><div class="ring-inner">0%</div></div><div class="match-label">match</div></div>`;
  return card;
}
async function runSearchDemo(){
  const list=SEARCH_SC[curLang], L=LBL[curLang];
  const sc=list[sIdx%list.length]; sIdx++;
  const typed=document.getElementById("typedText"),cursor=document.getElementById("cursor"),
    box=document.getElementById("searchBox"),status=document.getElementById("searchStatus"),
    label=document.getElementById("statusLabel"),cFH=document.getElementById("chipFH"),
    cHH=document.getElementById("chipHH"),cLI=document.getElementById("chipLI"),
    results=document.getElementById("results"),summary=document.getElementById("summary1");
  typed.innerHTML=`<span class="placeholder">${L.ph}</span>`;
  cursor.style.display="none";box.classList.remove("active");
  status.classList.remove("visible","finished");
  cFH.className="source-chip own pending";cFH.textContent=L.own;
  cHH.className="source-chip";cLI.className="source-chip";
  label.textContent=L.searching;results.innerHTML="";summary.classList.remove("visible");
  await sleep(500);
  box.classList.add("active");cursor.style.display="inline-block";
  if(reducedMotion){typed.textContent=sc.query;}else{await typeText(typed,sc.query);}
  await sleep(450);cursor.style.display="none";
  status.classList.add("visible");await sleep(600);
  cFH.classList.remove("pending");cFH.classList.add("on");await sleep(850);
  cFH.classList.remove("on");cFH.classList.add("done");cHH.classList.add("on");await sleep(800);
  cHH.classList.remove("on");cHH.classList.add("done");cLI.classList.add("on");await sleep(800);
  cLI.classList.remove("on");cLI.classList.add("done");
  label.textContent=L.ranking;await sleep(700);
  status.classList.add("finished");label.textContent=L.done;
  for(const c of sc.candidates){
    const card=buildCard(c);results.appendChild(card);
    const ring=card.querySelector(".ring2"),inner=card.querySelector(".ring-inner");
    requestAnimationFrame(()=>requestAnimationFrame(()=>{card.classList.add("visible");animateRing(ring,inner,c.match);}));
    await sleep(320);
  }
  await sleep(500);
  summary.innerHTML=L.found(sc.found,sc.seconds);
  summary.classList.add("visible");
  setTimeout(runSearchDemo,5000);
}
new IntersectionObserver((es,obs)=>{if(es[0].isIntersecting){obs.disconnect();runSearchDemo();}},{threshold:.35}).observe(document.getElementById("flyhuntDemo"));

