let cIdx=0, curPhoto='madina';
function scrollToBottom(el){el.scrollTop=el.scrollHeight;}
async function showTyping(body,ms){
  const t=document.createElement("div");t.className="typing";t.innerHTML="<i></i><i></i><i></i>";
  body.appendChild(t);requestAnimationFrame(()=>t.classList.add("visible"));
  scrollToBottom(body);await sleep(reducedMotion?80:ms);t.remove();
}
async function addMessage(body,from,text){
  if(from==="bot")await showTyping(body,900+Math.random()*500);else await sleep(reducedMotion?60:450);
  let node;
  const m=document.createElement("div");m.className="msg "+from;m.textContent=text;
  if(from==="user"){
    node=document.createElement("div");node.className="urow";
    node.appendChild(m);
    const f=document.createElement("div");f.className="uface";f.innerHTML=`<img src="${PHOTO[curPhoto]}" alt="">`;
    node.appendChild(f);
  } else node=m;
  body.appendChild(node);
  requestAnimationFrame(()=>{node.classList.add("visible");m.classList.add("visible");});
  scrollToBottom(body);await sleep(reducedMotion?60:250);
}
async function addCalendar(body,slots,pickIndex){
  await showTyping(body,700);
  const card=document.createElement("div");card.className="calendar-card";
  card.innerHTML=`<div class="calendar-title">${LBL[curLang].cal}</div>
    <div class="slots">${slots.map((s,i)=>`<span class="slot" data-i="${i}">${s}</span>`).join("")}</div>`;
  body.appendChild(card);requestAnimationFrame(()=>card.classList.add("visible"));
  scrollToBottom(body);await sleep(reducedMotion?100:900);
  card.querySelector(`.slot[data-i="${pickIndex}"]`).classList.add("picked");
  await sleep(reducedMotion?60:500);
}
function showReminder(container,text){
  const r=document.createElement("div");r.className="reminder";
  r.innerHTML=`<div class="reminder-icon">🔔</div><div><div class="reminder-title">${LBL[curLang].rem}</div><div class="reminder-text">${text}</div></div>`;
  container.appendChild(r);requestAnimationFrame(()=>r.classList.add("visible"));
}
async function runChatDemo(){
  const list=CHAT_SC[curLang];
  const sc=list[cIdx%list.length]; cIdx++;
  curPhoto=sc.photo;
  const body=document.getElementById("chatBody"),subtitle=document.getElementById("chatSubtitle"),
    summary=document.getElementById("chatSummary"),win=document.getElementById("flyhuntChatDemo");
  body.innerHTML="";win.querySelectorAll(".reminder").forEach(el=>el.remove());
  summary.classList.remove("visible");subtitle.textContent=sc.subtitle;
  await sleep(400);
  for(const step of sc.steps){
    if(step.from)await addMessage(body,step.from,step.text);
    else if(step.calendar)await addCalendar(body,step.calendar,step.pick);
    else if(step.reminder){await sleep(500);showReminder(win,step.reminder.text);}
  }
  await sleep(400);
  summary.innerHTML=LBL[curLang].chatSum;
  summary.classList.add("visible");
  setTimeout(runChatDemo,5500);
}
new IntersectionObserver((es,obs)=>{if(es[0].isIntersecting){obs.disconnect();runChatDemo();}},{threshold:.3}).observe(document.getElementById("flyhuntChatDemo"));

